def merge_intervals(intervals):
    if not intervals:
        return []
    items = sorted(intervals, key=lambda x: x[0])
    merged = [list(items[0])]
    for cur in items[1:]:
        if cur[0] <= merged[-1][1]:
            merged[-1][1] = max(merged[-1][1], cur[1])
        else:
            merged.append(list(cur))
    return merged

